function useTimer(initialMs: number) {
  const [ms, setMs] = useState(initialMs);
  useEffect(() => {
    if (ms <= 0) return;
    const id = setInterval(() => setMs(m => Math.max(0, m - 1000)), 1000);
    return () => clearInterval(id);  // always clear
  }, [ms <= 0]);  // restart effect when zero reached
  return ms;
}

