fixed_code:
function sortBy<T, K extends keyof T>(items: T[], field: K, dir: 'asc' | 'desc' = 'asc'): T[] {
  return [...items].sort((a, b) => {
    const av = a[field];
    const bv = b[field];
    const cmp = typeof av === 'string' && typeof bv === 'string'
      ? av.localeCompare(bv)
      : Number(av) - Number(bv);
    return dir === 'asc' ? cmp : -cmp;
  });
}

